import{_ as i,o as t,c as o,a2 as a}from"./chunks/framework.D2pTuMig.js";const g=JSON.parse('{"title":"Guide de Conception","description":"","frontmatter":{"title":"Guide de Conception"},"headers":[],"relativePath":"docs/fr/advertisers/sponsored-mail/design-guide/index.md","filePath":"docs/fr/advertisers/sponsored-mail/design-guide/index.md"}'),s={name:"docs/fr/advertisers/sponsored-mail/design-guide/index.md"};function r(n,e,l,d,c,u){return t(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="guide-de-conception" tabindex="-1">Guide de Conception <a class="header-anchor" href="#guide-de-conception" aria-label="Permalink to &quot;Guide de Conception&quot;">​</a></h1><p>De la stratégie créative à la validation technique : tout ce qu&#39;il faut savoir pour créer un flyer qui convertit.</p><div class="warning custom-block"><p class="custom-block-title">Validation obligatoire</p><p>Aucun contenu n&#39;est diffusé à un distributeur sans validation préalable de getinside via la plateforme. Soumettez votre BAT numérique avant toute impression.</p></div><hr><h2 id="process-de-validation" tabindex="-1">Process de validation <a class="header-anchor" href="#process-de-validation" aria-label="Permalink to &quot;Process de validation&quot;">​</a></h2><div class="gi-step"><div class="gi-step-num">1</div><div class="gi-step-body"><h3>Stratégie</h3><p>Définissez votre mécanique (promo, jeu, contenu…) et votre offre. C&#39;est la base de tout.</p></div></div><div class="gi-step"><div class="gi-step-num">2</div><div class="gi-step-body"><h3>Création</h3><p>Créez votre visuel en respectant les <a href="./print-specs">spécifications techniques</a> (formats, colorimétrie, QR code).</p></div></div><div class="gi-step"><div class="gi-step-num">3</div><div class="gi-step-body"><h3>Légal</h3><p>Intégrez toutes les <a href="./legal">mentions légales</a> obligatoires (identification, Triman, mentions sectorielles).</p></div></div><div class="gi-step"><div class="gi-step-num done">4</div><div class="gi-step-body"><h3>BAT &amp; Validation</h3><p>Soumettez votre BAT numérique sur la plateforme. getinside valide avant toute impression.</p></div></div><hr><h2 id="strategie-mecaniques" tabindex="-1">Stratégie &amp; Mécaniques <a class="header-anchor" href="#strategie-mecaniques" aria-label="Permalink to &quot;Stratégie &amp; Mécaniques&quot;">​</a></h2><p>Choisissez la mécanique adaptée à votre objectif. Toutes fonctionnent avec un QR code comme point d&#39;entrée.</p><div class="gi-value-grid"><div class="gi-value-card"><strong>🏷️ Promotion</strong><p><em>&quot;Scannez pour obtenir une offre exclusive&quot;</em></p><p>Idéal pour la conversion immédiate en ligne. La mécanique la plus directe.</p></div><div class="gi-value-card"><strong>🏪 Drive to Store</strong><p><em>&quot;Présentez cette carte en boutique pour un café offert&quot;</em></p><p>Génère du trafic physique. Fonctionne aussi en hybride Web + Magasin.</p></div><div class="gi-value-card"><strong>📚 Contenu Éducatif</strong><p><em>&quot;Scannez pour découvrir nos 5 recettes de saison&quot;</em></p><p>Pour l&#39;image de marque et l&#39;engagement long terme.</p></div><div class="gi-value-card"><strong>🎲 Jeux / Concours</strong><p><em>&quot;Flashez pour tourner la roue&quot;</em></p><p>Idéal pour la collecte de leads qualifiés.</p></div><div class="gi-value-card"><strong>📱 Drive to App</strong><p><em>&quot;Téléchargez l&#39;app pour débloquer vos points&quot;</em></p><p>Pour l&#39;acquisition d&#39;utilisateurs mobiles.</p></div><div class="gi-value-card"><strong>⭐ Feedback</strong><p><em>&quot;Donnez votre avis contre un cadeau&quot;</em></p><p>Pour enrichir la connaissance client et générer des avis vérifiés.</p></div></div><hr><h2 id="l-offre-ce-qui-fait-la-difference" tabindex="-1">L&#39;Offre : ce qui fait la différence <a class="header-anchor" href="#l-offre-ce-qui-fait-la-difference" aria-label="Permalink to &quot;L&#39;Offre : ce qui fait la différence&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Privilégiez la valeur monétaire</p><p><strong>&quot;10€ offerts&quot;</strong> convertit beaucoup mieux que &quot;-10% de réduction&quot;. La valeur concrète est immédiatement perçue. Un produit offert ou un cadeau fonctionnent aussi très bien — le levier psychologique du cadeau surpasse celui de l&#39;économie.</p></div><div class="info custom-block"><p class="custom-block-title">Durée de validité</p><p>Prévoyez une validité d&#39;<strong>au moins 3 mois</strong>. Les destinataires conservent souvent les flyers plusieurs semaines avant de les scanner. Une offre expirée = une opportunité perdue.</p></div><hr><h2 id="mobile-first" tabindex="-1">Mobile First <a class="header-anchor" href="#mobile-first" aria-label="Permalink to &quot;Mobile First&quot;">​</a></h2><p>L&#39;expérience post-scan se fait à <strong>99% sur smartphone</strong>. Votre landing page doit être prête avant l&#39;impression.</p><div class="info custom-block"><p class="custom-block-title">3 règles non négociables</p><ol><li><strong>Responsive</strong> — la page doit s&#39;adapter parfaitement aux petits écrans.</li><li><strong>Rapide</strong> — le chargement doit être immédiat même en 3G/4G.</li><li><strong>Simple</strong> — un seul formulaire court, un seul appel à l&#39;action.</li></ol></div><hr><h2 id="ressources" tabindex="-1">Ressources <a class="header-anchor" href="#ressources" aria-label="Permalink to &quot;Ressources&quot;">​</a></h2><ul><li><strong><a href="https://docs.google.com/presentation/d/1pHOKuOtkHXMaKd0qxng7XgF4oS-cjOBe9EtF3b-6XzU/edit" target="_blank">✨ Exemples &amp; Inspirations</a></strong> — Google Slides avec des campagnes réussies.</li><li><strong><a href="https://drive.google.com/drive/folders/1rbTKAXw8z-8xoy-_PhK9ICL_zb9do7xe" target="_blank">📂 Gabarits .ai/.pdf</a></strong> — Formats A5 et A6 avec fond perdu et zones tranquilles pré-tracées.</li><li><strong><a href="https://drive.google.com/drive/folders/1ORm6uAhsIWCCFWhOl-NjO4tKfiGQdLNy" target="_blank">🖼️ Logos Obligatoires</a></strong> — Logo getinside, Triman, Info-tri (Loi AGEC).</li><li><strong><a href="https://docs.google.com/document/d/17oybJkf4iOX0XrC4LOJSI0zp2y0w_Wn7F4GW_oBAZcM/edit" target="_blank">✅ Check-list de Contrôle</a></strong> — À compléter avant chaque soumission de BAT.</li></ul><div class="info custom-block"><p class="custom-block-title">Pas de graphiste en interne ?</p><p>Notre <strong>Studio Créatif</strong> prend en charge la direction artistique, l&#39;exécution et la mise aux normes — pour un forfait de <strong>550€ HT</strong> par campagne. → <a href="/handbook/docs/fr/resources/studio.html">Contacter le Studio</a></p></div>',25)])])}const m=i(s,[["render",r]]);export{g as __pageData,m as default};
